#top-titlebar :is(.ty-menu-btn-area-sub1, .ty-menu-btn-area-sub2, .ty-menu-btn-area-sub3),
.ty-md-radio-button-off::before,
.ion-chevron-left::before,
.ion-checkmark::before,
.fa-code::before {
    color: var(--a-c);
    vertical-align: middle;
}

&.swiper-button-disabled {
	background-color: var(--theme-bg2-color, #f4f5f7);
	border-color: var(--theme-bg2-color, #f4f5f7);
	cursor: not-allowed;
}

@font-face {
  font-family: 'Font Awesome 6 Brands';
  font-style: normal;
  font-weight: 400;
  font-display: @fa-font-display;
  src: url('@{fa-font-path}/fa-brands-400.woff2') format('woff2'),
    url('@{fa-font-path}/fa-brands-400.ttf') format('truetype');
}

@font-face {
  font-family: 'Font Awesome 6 Free';
  font-style: normal;
  font-weight: 400;
  font-display: @fa-font-display;
  src: url('@{fa-font-path}/fa-regular-400.woff2') format('woff2'),
    url('@{fa-font-path}/fa-regular-400.ttf') format('truetype');
}

h3.mcate-item-hd {
  font-size: var(--tv-FallMenu-box-font-size);
  border-bottom: 0 solid #ccc;
  color: var(--tv-FallMenu-box-title-text-color);
  font-weight: 700;
  margin: 0;
  line-height: 32px;
}

&__empty-text {
  @apply absolute;
  @apply ~'top-1/2';
  @apply ~'left-1/2';
  @apply ~'-translate-x-2/4' ~'-translate-y-2/4';
  @apply text-center;
  @apply text-color-text-placeholder;
}

&:not(.full-width) {
  @apply border-l border-l-color-bg-3;
  @apply h-full;
  @apply overflow-y-auto;
  max-height: ~'calc(66vh - 56px)';
  @apply pl-8 pr-8;
  @apply ~'pt-2.5';
}

svg {
  @apply w-12;
  @apply h-12;
  @apply absolute;
  @apply ~'top-1/2';
  @apply ~'left-1/2';
  @apply ~'-translate-x-2/4' ~'-translate-y-2/4';
}

&:not(.Post--by-actor):not(.Post--byCurrentUser) .Post-body {
  border-radius: 4px 20px 20px 20px !important;
}

&:not(.Post--byCurrentUser):not(.Post--by-actor) .Post-body {
  border-radius: 4px 20px 20px 4px !important;
}

> h3 {
  margin: 0;
  font-size: 18px;
  line-height: 1.1;
  font-weight: 800;
  color: var(--home-title);
  .avocado-truncate();
}

&__close-btn {
  position: absolute;
  top: @spacer-2;
  right: @spacer-2;
  margin: calc(-1 * @spacer-1);
  padding: @spacer-1;
  color: @calendar-title-color;
}

&.weui-btn_disabled,
    &[disabled] {
      color: rgba(0, 0, 0, 0.15);
      color: var(--weui-FG-4);
      background-color: rgba(0, 0, 0, 0.05);
      background-color: var(--weui-FG-5);
    }

body,
.wx-root,
page {
  --weui-BTN-HEIGHT: 48;
  --weui-BTN-HEIGHT-MEDIUM: 40;
  --weui-BTN-HEIGHT-SMALL: 32;
}

&::before {
  position: absolute;
  top: calc(var(--van-padding-xs) * -1);
  right: 0;
  bottom: calc(var(--van-padding-xs) * -1);
  left: 0;
  content: '';
}
